export const MEDICAL_MODEL_IDS = Object.keys(MEDICAL_MODELS);
export function listMedicalModels(category, tag) {
    let models = Object.values(MEDICAL_MODELS);
    if (category) {
        models = models.filter((m) => m.category === category);
    }
    if (tag) {
        models = models.filter((m) => m.tags.includes(tag));
    }
    return models;
}
export function getMedicalModel(id) {
    return MEDICAL_MODELS[id];
}
export function formatModelList(models) {
    if (models.length === 0) {
        return "No models found matching the specified filters.";
    }
    const header = `## Free Medical 3D Models (${models.length})\n\n`;
    const rows = models
        .map((m) => `### \`${m.id}\`\n**${m.name}** — *${m.category}*\n${m.description}\n- **Source:** [${m.source}](${m.sourceUrl})\n- **Format:** ${m.format}\n- **License:** ${m.license}\n- **Tags:** ${m.tags.join(", ")}`)
        .join("\n\n---\n\n");
    return header + rows;
}
